import { state, elements, getHeight, getWrapper, SECTIONS } from "./init.js";
import { updateFontStyles } from "../lib/font-styles.js";
import { LAYOUTS } from "../lib/layouts.js";
import { update as updateHeader } from "../lib/header.js";
import { update as updateFooter } from "../lib/footer.js";

function update() {
	updateFontStyles();
	updateHeader();
	updateFooter();
	updateBackground();

	var wrapper_style = elements.wrapper.style;
	wrapper_style.display = "flex";
	wrapper_style.height = "100vh"; // reset to take up page height
	wrapper_style.color = state.font_color;
	wrapper_style.maxWidth =
		state.max_width_target == "wrapper" ? state.max_width + "px" : "";
	wrapper_style.marginLeft =
		state.max_width_target == "wrapper" && state.max_width_align != "left"
			? "auto"
			: "";
	wrapper_style.marginRight =
		state.max_width_target == "wrapper" && state.max_width_align != "right"
			? "auto"
			: "";
	wrapper_style.padding =
		state.margin_top +
		"rem " +
		state.margin_right +
		"rem " +
		state.margin_bottom +
		"rem " +
		state.margin_left +
		"rem";
	wrapper_style.borderTop = state.border.enabled
		? state.border.top.width +
			"px " +
			state.border.top.style +
			" " +
			state.border.top.color
		: "";
	wrapper_style.borderRight = state.border.enabled
		? state.border.right.width +
			"px " +
			state.border.right.style +
			" " +
			state.border.right.color
		: "";
	wrapper_style.borderBottom = state.border.enabled
		? state.border.bottom.width +
			"px " +
			state.border.bottom.style +
			" " +
			state.border.bottom.color
		: "";
	wrapper_style.borderLeft = state.border.enabled
		? state.border.left.width +
			"px " +
			state.border.left.style +
			" " +
			state.border.left.color
		: "";

	var p_style = elements.primary.outer.style;
	var l_style = elements.legend.outer.style;

	var selected_layout = getLayoutOrder();
	if (selected_layout.mode == "stack")
		selected_layout.elements.forEach(function (el, i) {
			elements[el].outer.style.order = 10 * i;
		});
	else {
		for (var el in selected_layout.elements) {
			for (var prop in selected_layout.elements[el]) {
				var target = elements[el].outer || elements[el];
				target.style[prop] = selected_layout.elements[el][prop];
				target.style.order = "";
			}
		}
	}

	// Resetting the "display" style of each section, as it
	// might've been previously hidden
	elements.header.outer.style.display = "";
	elements.footer.outer.style.display = "";
	elements.controls.outer.style.display = "";
	p_style.display = "flex";
	l_style.display = "";

	p_style.flex = "1 1 auto";
	p_style.height = null;

	elements.primary.outer.style.maxWidth =
		state.max_width_target == "primary" ? state.max_width + "px" : "";
	elements.primary.outer.style.marginLeft =
		state.max_width_target == "primary" && state.max_width_align != "left"
			? "auto"
			: "";
	elements.primary.outer.style.marginRight =
		state.max_width_target == "primary" && state.max_width_align != "right"
			? "auto"
			: "";

	var use_screenreader_text = state.screenreader_text_primary.trim() != "";
	var description_node = document.getElementById(
		"fl-layout-primary-description",
	);
	elements.primary.outer.setAttribute(
		"aria-label",
		"primary visualisation container",
	);
	description_node.innerText = state.screenreader_text_primary;
	use_screenreader_text
		? elements.primary.outer.setAttribute(
				"aria-describedBy",
				"fl-layout-primary-description",
			)
		: elements.primary.outer.removeAttribute("aria-describedBy");
	state.screenreader_hide_primary
		? elements.primary.inner.setAttribute("aria-hidden", true)
		: elements.primary.inner.removeAttribute("aria-hidden");

	state.screenreader_label.trim() != ""
		? getWrapper().setAttribute("aria-label", state.screenreader_label)
		: getWrapper().removeAttribute("aria-label");

	SECTIONS.map(function (el) {
		var containers = elements[el];
		var style = containers.outer.style;
		var inner = containers.inner;
		return {
			name: el,
			height: getHeight(inner),
			order: parseFloat(style.order),
			style: style,
		};
	})
		.sort(function (a, b) {
			return a.order - b.order;
		})
		.filter(function (obj) {
			if (obj.height || obj.name == "primary") return true;
			// If a section has no height we remove the padding and set it to display: none
			// This is to make sure that empty sections don't take up unnecessary space
			// We exclude the primary container from this logic, as that container usually
			// gets filled after layout.update() gets called and therefore don't want to
			// hide if it's empty at this point
			obj.style.paddingBottom = "";
			obj.style.paddingTop = "";
			obj.style.display = "none";
		})
		.forEach(function (obj, i, arr) {
			obj.style.width = "100%";
			obj.style.paddingTop = i ? getMargin("padding") : "";
			obj.style.paddingBottom = i < arr.length - 1 ? getMargin("padding") : "";
		});

	elements.wrapper.style.gridColumnGap = getMargin("gap");
	elements.wrapper.style.gridRowGap = getMargin("gap");

	document.body.setAttribute("dir", state.read_direction);
	elements.wrapper.setAttribute("dir", state.read_direction);
	document.getElementById("fl-layout-wrapper-outer").setAttribute("dir", "ltr");
}

function getLayoutOrder() {
	var is_mobile = window.innerWidth < state.breakpoint_mobile_big;
	var is_grid = state.layout_order.indexOf("grid") > -1;
	var layout = {
		id: state.layout_order,
		mode: is_grid ? "grid" : "stack",
		elements: LAYOUTS[state.layout_order],
	};
	if (is_mobile && is_grid) {
		(layout.id = "stack-default"),
			(layout.mode = "stack"),
			(layout.elements = LAYOUTS["stack-default"]);
	}
	return layout;
}

function getMargin(mode) {
	var current_layout = getLayoutOrder();
	var full_margin;
	if (state.space_between_sections == "custom")
		full_margin = state.space_between_sections_custom;
	else full_margin = state.space_between_sections;

	if (current_layout.mode == "grid")
		return mode == "gap" ? full_margin + "rem" : "";
	else return mode == "gap" ? "" : full_margin / 2 + "rem";
}

function updateBackground() {
	document.body.style.backgroundColor = state.background_color_enabled
		? state.background_color
		: "transparent";
	document.body.style.backgroundImage = state.background_image_enabled
		? "url(" + state.background_image_src + ")"
		: "";
	document.body.style.backgroundSize = state.background_image_size;
	document.body.style.backgroundRepeat = "no-repeat";
	document.body.style.backgroundPosition = state.background_image_position;
}

export { update, getLayoutOrder };
