import { createInterpreter } from "@flourish/interpreter";

const getInterpretation = createInterpreter.getInterpretation;

const DEFAULTS = Object.freeze({
	transform_labels: false,
	transform: "multiply",
	multiply_divide_constant: 1,
	exponentiate_constant: 0,
	multiplier: 1,
	prefix: "",
	n_dec: 2,
	suffix: "",
	strip_zeros: true,
	strip_separator: true,
	negative_sign: "-$nk",
	show_positive_sign: false,
});

function round(val, pow) {
	// Round here before passing into the formatter, as the formatter has an issue with rounding floating point numbers (FLOURISH-3591)
	const roundAwayFromZero = (x) => Math.round(Math.abs(x)) * Math.sign(x);
	pow = pow > 0 ? Math.floor(pow) : Math.ceil(pow);
	if (!pow) return roundAwayFromZero(val);
	const rounder = Math.pow(10, Math.abs(pow));
	return pow > 0
		? roundAwayFromZero(val * rounder) / rounder
		: roundAwayFromZero(val / rounder) * rounder;
}

function getTransformFunction(state) {
	let constant = 1;
	if (state.transform_labels) {
		if (state.transform === "multiply")
			constant = state.multiply_divide_constant;
		else if (state.transform === "divide")
			constant = 1 / state.multiply_divide_constant;
		else constant = Math.pow(10, state.exponentiate_constant);
	}
	return function (x) {
		return x * constant;
	};
}

function makeNumberFormatter(state, format_id) {
	const interp = getInterpretation(format_id);
	if (!interp) throw new Error(`format_id ${format_id} not recognised`);
	if (interp.type !== "number")
		throw new Error(`format_id ${format_id}not a number format`);
	const formatterFunction = interp.format;
	const decimal = interp.decimal_mark;
	const thousands = interp.thousand_separator;
	const n_dec = Math.trunc(state.n_dec);
	const spec = (thousands ? "," : "") + "." + Math.max(0, n_dec) + "f";
	const form = function (value) {
		return formatterFunction(value, spec);
	};
	const strip_zeros_regex =
		state.strip_zeros && n_dec > 0 ? new RegExp("\\" + decimal + "?0+$") : null;
	const may_strip_separator = state.strip_separator && thousands;
	const neg_sign = state.negative_sign;
	const show_pos_sign = state.show_positive_sign;
	const transform = getTransformFunction(state);

	return function (val) {
		if (val === null) return "";

		const num = round(transform(val), n_dec);
		const is_negative = num < 0;
		const abs_num = Math.abs(num);
		const strip_separator =
			may_strip_separator && thousands && abs_num >= 1000 && abs_num < 10000;
		let num_string = form(abs_num);
		if (strip_zeros_regex)
			num_string = num_string.replace(strip_zeros_regex, "");
		if (strip_separator) num_string = num_string.replace(thousands, "");
		if (!is_negative && neg_sign === "$-nk" && show_pos_sign)
			return state.prefix + "+" + num_string + state.suffix;
		if (!is_negative && neg_sign === "-$nk" && show_pos_sign)
			return "+" + state.prefix + num_string + state.suffix;
		if (!is_negative || neg_sign === "none")
			return state.prefix + num_string + state.suffix;
		if (neg_sign === "-$nk")
			return "-" + state.prefix + num_string + state.suffix;
		if (neg_sign === "$-nk")
			return state.prefix + "-" + num_string + state.suffix;
		if (neg_sign === "($nk)")
			return "(" + state.prefix + num_string + state.suffix + ")";
		return state.prefix + "(" + num_string + ")" + state.suffix;
	};
}

function initNumberFormatter(state) {
	for (let key in DEFAULTS) {
		if (state[key] === undefined) state[key] = DEFAULTS[key];
	}

	return function (format_id) {
		return makeNumberFormatter(state, format_id);
	};
}

export { initNumberFormatter };
